package com.google.gson;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.lang.reflect.Field;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

class GsonBuilderTest {

  private GsonBuilder gsonBuilder;

  @BeforeEach
  void setUp() {
    gsonBuilder = new GsonBuilder();
  }

  @Test
  void testSetDateFormat_withValidPattern_shouldSetDatePattern() throws Exception {
    String pattern = "yyyy-MM-dd";

    GsonBuilder returned = gsonBuilder.setDateFormat(pattern);

    assertSame(gsonBuilder, returned);
    // Use reflection to verify private field datePattern
    Field datePatternField = GsonBuilder.class.getDeclaredField("datePattern");
    datePatternField.setAccessible(true);
    String actualPattern = (String) datePatternField.get(gsonBuilder);
    assertEquals(pattern, actualPattern);
  }

  @Test
  void testSetDateFormat_withNullPattern_shouldSetDatePatternToNull() throws Exception {
    String pattern = null;

    GsonBuilder returned = gsonBuilder.setDateFormat(pattern);

    assertSame(gsonBuilder, returned);
    Field datePatternField = GsonBuilder.class.getDeclaredField("datePattern");
    datePatternField.setAccessible(true);
    String actualPattern = (String) datePatternField.get(gsonBuilder);
    assertNull(actualPattern);
  }
}
